import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"The Imperial March","description":"","frontmatter":{},"headers":[],"relativePath":"guide/worlds/imperial-palace.md","filePath":"guide/worlds/imperial-palace.md","lastUpdated":1782031809000}'),d={name:"guide/worlds/imperial-palace.md"};function n(i,e,s,c,l,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="the-imperial-march" tabindex="-1">The Imperial March <a class="header-anchor" href="#the-imperial-march" aria-label="Permalink to &quot;The Imperial March&quot;">​</a></h1><p><strong>Zone role:</strong> Empire lands, the palace seat, the attack/defend map.</p><p><strong>Design promise:</strong> A fortified palace plaza that reads differently depending on who you are — the seat you are sworn to <strong>hold</strong> as a Palace Guard, or the crown you have come to <strong>raid</strong> as an Elf or Villain. The third of the four canonical zones (E8.1 / FLO-427).</p><blockquote><p><strong>Content binding.</strong> This spec is the prose brief; the zone&#39;s landmark and encounter data lives in <code>src/game/world/zoneContent.ts</code> under the <code>empire</code> key (<code>getZoneContent(&#39;empire&#39;)</code>), and the scene is <code>src/scenes/empireScene.ts</code>. See <a href="./../decisions/0004-world-spec-to-zone-binding">ADR-0004</a>.</p></blockquote><h2 id="lore" tabindex="-1">Lore <a class="header-anchor" href="#lore" aria-label="Permalink to &quot;Lore&quot;">​</a></h2><p>The Imperial March is the crown&#39;s parade ground and last wall — a pale-stone plaza beneath the palace keep where the Emperor musters the Palace Guard, receives tribute wagons from the Salt Road, and stages the columns that push into the forest. To the Guard it is home and duty: the keep is the commander&#39;s seat, and the standing order is simple — hold the line. To the Forest Elves it is the source of every axe in Lysaen; to the Villain it is the throat of the Empire. Both come to the same plaza for opposite reasons.</p><h2 id="mood-and-visual-language" tabindex="-1">Mood and visual language <a class="header-anchor" href="#mood-and-visual-language" aria-label="Permalink to &quot;Mood and visual language&quot;">​</a></h2><ul><li>Pale crown stone, imperial gold banners, straight fortified lines — the opposite of the forest&#39;s organic clutter and the Salt Road&#39;s patched reuse.</li><li>The <strong>palace keep</strong> dominates the skyline as the orientation landmark and the objective focus; the <strong>crown gate</strong> funnels the approach; the <strong>banner pillar</strong> marks the march.</li><li>Guard props should look numbered, drilled, and intrusive — an occupying order, not a lived-in place.</li></ul><h2 id="player-facing-flow" tabindex="-1">Player-facing flow <a class="header-anchor" href="#player-facing-flow" aria-label="Permalink to &quot;Player-facing flow&quot;">​</a></h2><ol><li>Spawn on the plaza approach with the keep ahead and the crown gate between.</li><li>Read your <strong>standing order</strong> from the HUD directive (defend vs raid — derived from your faction&#39;s stance toward the Empire, see below).</li><li>Engage the Palace-Guard patrols ringing the keep; a wall archer covers the approach from behind it.</li><li>Hit the tribute caravans on the outer roads to advance the raid/loot objective.</li><li>Press toward — or hold — the palace keep per your directive.</li></ol><h2 id="faction-directive-attack-defend" tabindex="-1">Faction directive (attack / defend) <a class="header-anchor" href="#faction-directive-attack-defend" aria-label="Permalink to &quot;Faction directive (attack / defend)&quot;">​</a></h2><p>The same zone surfaces an asymmetric standing order, resolved from the player&#39;s faction stance toward the Empire via <code>getZoneDirective(zoneId, playerFactionId)</code> (<code>src/game/world/zoneDirectives.ts</code>, reusing the faction <code>resolveStance</code> matrix):</p><table tabindex="0"><thead><tr><th>Player faction</th><th>Stance vs Empire</th><th>Directive</th><th>Summary</th></tr></thead><tbody><tr><td>Palace Guard (<code>empire</code>)</td><td>allied</td><td><strong>defend</strong></td><td>Hold the palace and the crown roads (the E4.3 commander&#39;s seat).</td></tr><tr><td>Forest Elf (<code>forestElves</code>)</td><td>hostile</td><td><strong>raid</strong></td><td>Strike the crown&#39;s caravans and patrols.</td></tr><tr><td>Villain (<code>villain</code>)</td><td>hostile</td><td><strong>raid</strong></td><td>Lay siege to the Imperial palace.</td></tr><tr><td>Unaffiliated (<code>neutral</code>)</td><td>neutral</td><td><strong>patrol</strong></td><td>Keep the peace on the march.</td></tr></tbody></table><p>The directive is <em>flavour and direction only</em> — the win condition stays the caravan-raid count (<code>gameSlice</code> / <code>objectiveMachine</code>). It exists so the zone is never directionless and so the palace reads correctly for both attackers and defenders.</p><h2 id="landmark-briefs" tabindex="-1">Landmark briefs <a class="header-anchor" href="#landmark-briefs" aria-label="Permalink to &quot;Landmark briefs&quot;">​</a></h2><p>Greybox boxes today (swapped for streamed GLBs via each landmark&#39;s <code>assetKey</code> when the palace assets land). Ids match <code>zoneContent.ts</code>.</p><table tabindex="0"><thead><tr><th>Id</th><th>Role</th></tr></thead><tbody><tr><td><code>palace-keep</code></td><td>Imperial palace keep — objective focus / commander seat (E4.3).</td></tr><tr><td><code>crown-gate</code></td><td>Crown gate — fortified palace approach / escalation point.</td></tr><tr><td><code>guard-barracks</code></td><td>Palace-guard barracks — patrol muster point.</td></tr><tr><td><code>crown-banner</code></td><td>Crown banner pillar — imperial march marker / silhouette.</td></tr></tbody></table><h2 id="encounter-hooks" tabindex="-1">Encounter hooks <a class="header-anchor" href="#encounter-hooks" aria-label="Permalink to &quot;Encounter hooks&quot;">​</a></h2><p>The Palace-Guard patrols use the placeholder <code>soldier</code> archetype until the dedicated palace-guard asset lands (pending; depends on Pygmalion). Ids match <code>zoneContent.ts</code>.</p><table tabindex="0"><thead><tr><th>Id</th><th>Kind</th><th>Role</th></tr></thead><tbody><tr><td><code>guard-1</code>..<code>guard-4</code></td><td>soldier</td><td>Palace-Guard patrols ringing the keep.</td></tr><tr><td><code>wall-archer-1</code></td><td>archer</td><td>Wall archer covering the approach behind the keep.</td></tr><tr><td><code>tribute-1</code>, <code>tribute-2</code></td><td>caravan</td><td>Tribute wagons on the outer roads — raid/loot targets.</td></tr></tbody></table><h2 id="asset-needs" tabindex="-1">Asset needs <a class="header-anchor" href="#asset-needs" aria-label="Permalink to &quot;Asset needs&quot;">​</a></h2><ul><li><strong>Palace-guard archetype/GLB</strong> (pending, Pygmalion) — replaces the placeholder <code>soldier</code> mesh once available; no scene change needed (swap the archetype).</li><li><strong>Palace structures</strong> (keep, gate, barracks, banner) — replace the greybox landmarks via <code>assetKey</code> + the <code>zone.empire</code> streaming manifest (<code>src/game/streaming/zoneManifests.ts</code>, currently empty placements).</li></ul>',22)])])}const u=t(d,[["render",n]]);export{m as __pageData,u as default};
